return ['x-generator'=>'GlotPress/4.0.3','translation-revision-date'=>'2026-04-23 23:00:35+0000','plural-forms'=>'nplurals=2; plural=n != 1;','project-id-version'=>'Plugins - Akismet Anti-spam: Spam Protection - Stable (latest release)','language'=>'de','messages'=>['Would you like to <a href="%s">scan pending comments for spam</a>?'=>'Möchten Sie <a href="%s">ausstehende Kommentare auf Spam überprüfen</a>?','Get started'=>'Erste Schritte','Name your own price for personal sites. Businesses start on a paid plan.'=>'Legen Sie Ihren eigenen Preis für private Websites fest. Unternehmen beginnen mit einem kostenpflichtigen Tarif.','Flexible pricing'=>'Flexible Preise','Seamlessly integrates with plugins like Elementor, Contact Form 7, Jetpack and WPForms.'=>'Nahtlose Integration mit Plugins wie Elementor, Contact Form 7, Jetpack und WPForms.','Works with popular contact forms'=>'Funktioniert mit gängigen Kontaktformularen','Akismet runs quietly in the background, saving you hours of manual moderation.'=>'Akismet läuft unbemerkt im Hintergrund und erspart Ihnen stundenlange manuelle Moderation.','Zero effort'=>'Keinerlei Aufwand','Learns from billions of spam signals across the web to stop junk before it reaches you.'=>'Lernt aus Milliarden von Spam-Signalen im Internet, um Junk-Mails zu stoppen, bevor sie Sie erreichen.','Machine learning accuracy'=>'Genauigkeit durch maschinelles Lernen','Protect your site from comment spam and contact form spam — automatically.'=>'Schützen Sie Ihre Website automatisch vor Kommentar-Spam und Kontaktformular-Spam.','Want to use a different account? <a href="%s" class="akismet-external-link">Visit akismet.com</a> to set it up and get your API key.'=>'Möchten Sie ein anderes Konto verwenden? <a href="%s" class="akismet-external-link">Besuchen Sie akismet.com</a>, um es einzurichten und Ihren API-Schlüssel zu erhalten.','By connecting, we\'ll use your Jetpack account to activate Akismet on this site.'=>'Durch die Verbindung verwenden wir I